#!/usr/bin/env bash
# Generated by DaGhE Orchestrator
set -euo pipefail

# Calculate dynamic BASE_DIR for the wrapper too
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
export BASE_DIR="$(cd "${SCRIPT_DIR}/../.." && pwd)"

# Logic for locking
LOCK_FILE="${BASE_DIR}/state/daghe-youtube-search-metadata.lock"
exec 9>"$LOCK_FILE"
if ! flock -n 9; then
    echo "[$({date})] daghe-youtube-search-metadata: Already running, skipping."
    exit 0
fi

cd "${BASE_DIR}/jobs/daghe-youtube-search-metadata/current"
export PYTHONPATH="src"

# Run with uv
uv run python -m youtube_search_metadata.cli --config config/job.yaml
